package com.taskmind.backend.integration.infrastructure.persistence.jpa;
import com.taskmind.backend.integration.domain.model.*; import com.taskmind.backend.integration.domain.repository.IntegrationPublishRecordRepository; import java.sql.*; import java.time.Instant; import java.util.*; import org.springframework.jdbc.core.JdbcTemplate; import org.springframework.stereotype.Repository;
@Repository public class JdbcIntegrationPublishRecordRepository implements IntegrationPublishRecordRepository { private final JdbcTemplate jdbc; public JdbcIntegrationPublishRecordRepository(JdbcTemplate jdbc){this.jdbc=jdbc;} public IntegrationPublishRecord save(IntegrationPublishRecord r){jdbc.update("MERGE INTO integration_publish_records (id,version,task_id,project_link_id,provider,external_id,external_key,external_url,status,published_by,published_at,metadata_json) KEY(id) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)",r.id(),0,r.taskId(),r.projectLinkId(),r.provider().name(),r.externalId(),r.externalKey(),r.externalUrl(),r.status(),r.publishedBy(),r.publishedAt(),r.metadataJson());return r;} public Optional<IntegrationPublishRecord> findByTaskIdAndProjectLinkId(UUID taskId,UUID projectLinkId){return jdbc.query("SELECT * FROM integration_publish_records WHERE task_id=? AND project_link_id=? ORDER BY published_at LIMIT 1",this::map,taskId,projectLinkId).stream().findFirst();} private IntegrationPublishRecord map(ResultSet rs,int row)throws SQLException{return new IntegrationPublishRecord((UUID)rs.getObject("id"),rs.getLong("version"),(UUID)rs.getObject("task_id"),(UUID)rs.getObject("project_link_id"),IntegrationProvider.valueOf(rs.getString("provider")),rs.getString("external_id"),rs.getString("external_key"),rs.getString("external_url"),rs.getString("status"),(UUID)rs.getObject("published_by"),i(rs,"published_at"),rs.getString("metadata_json"));} private Instant i(ResultSet rs,String c)throws SQLException{java.sql.Timestamp ts=rs.getTimestamp(c);return ts==null?null:ts.toInstant();}}
